body {
    font-family: 'Arial', sans-serif;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
    color: #fff;
    min-height: 100vh;
    overflow-x: hidden;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 20px;
}

header {
    text-align: center;
    margin-bottom: 30px;
    animation: slideDown 0.6s ease;
}

header h1 {
    font-size: 3em;
    background: linear-gradient(45deg, #00d4ff, #0099ff);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin-bottom: 10px;
    text-shadow: 0 0 20px rgba(0, 212, 255, 0.3);
}

header p {
    font-size: 1.1em;
    color: #aaa;
}

/* Navigation */
.main-menu {
    display: flex;
    justify-content: center;
    gap: 15px;
    margin-bottom: 40px;
    flex-wrap: wrap;
}

.menu-btn {
    padding: 12px 30px;
    background: linear-gradient(45deg, #0099ff, #00d4ff);
    color: white;
    border: none;
    border-radius: 25px;
    font-size: 1em;
    cursor: pointer;
    transition: all 0.3s ease;
    box-shadow: 0 4px 15px rgba(0, 153, 255, 0.4);
}

.menu-btn:hover {
    transform: translateY(-3px);
    box-shadow: 0 6px 20px rgba(0, 212, 255, 0.6);
}

.menu-btn:active {
    transform: translateY(-1px);
}

/* Sections */
.section {
    display: none;
    animation: fadeIn 0.5s ease;
}

.section.active {
    display: block;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes slideDown {
    from {
        opacity: 0;
        transform: translateY(-20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Welcome Box */
.welcome-box {
    text-align: center;
    padding: 60px 40px;
    background: rgba(0, 153, 255, 0.1);
    border: 2px solid rgba(0, 212, 255, 0.3);
    border-radius: 15px;
    margin-bottom: 40px;
}

.welcome-box h2 {
    font-size: 2.5em;
    margin-bottom: 20px;
    color: #00d4ff;
}

.welcome-box p {
    font-size: 1.2em;
    margin-bottom: 40px;
