    transition: all 0.3s ease;
    box-shadow: 0 5px 20px rgba(0, 153, 255, 0.5);
}

.large-btn:hover {
    transform: scale(1.05);
    box-shadow: 0 8px 30px rgba(0, 212, 255, 0.7);
}

/* Games Grid */
.games-grid {
