{"branch": "games-website", "content": "// Section Management
function showSection(sectionId) {
    document.querySelectorAll('.section').forEach(s => s.classList.remove('active'));
    document.getElementById(sectionId).classList.add('active');
}

function backToGames() {
    showSection('games');
    document.getElementById('game-container').innerHTML = '';
}

// Game Loader
function loadGame(gameName) {
    const container = document.getElementById('game-container');
    container.innerHTML = '';

    let gameContent = '';

    switch(gameName) {
        case 'snake':
            gameContent = createSnakeGame();
            break;
        case 'flappy':
            gameContent = createFlappyGame();
            break;
        case '2048':
            gameContent = create2048Game();
            break;
        case 'tictactoe':
            gameContent = createTicTacToeGame();
            break;
        case 'breakout':
            gameContent = createBreakoutGame();
            break;
        case 'memory':
            gameContent = createMemoryGame();
            break;
        case 'pacman':
            gameContent = createPacManGame();
            break;
        case 'pong':
            gameContent = createPongGame();
            break;
    }

    container.innerHTML = gameContent;
    showSection('game-player');

    // Initialize game after content is added
    setTimeout(() => {
        initializeGame(gameName);
    }, 100);
}

// ========== SNAKE GAME ==========
function createSnakeGame() {
    return `
        <div style="text-align: center;">
            <h2>🐍 Snake Game</h2>
            <p>Use arrow keys to move. Eat the red food!</p>
            <canvas id="snakeCanvas" width="400" height="400"></canvas>
            <p id="snakeScore">Score: 0</p>
        </div>
    `;
}

function initializeSnakeGame() {
    const canvas = document.getElementById('snakeCanvas');
    const ctx = canvas.getContext('2d');

    let snake = [{x: 200, y: 200}];
    let food = {x: Math.random() * 380, y: Math.random() * 380};
    let score = 0;
    let direction = {x: 20, y: 0};
    let nextDirection = {x: 20, y: 0};
    let gameRunning = true;

    document.addEventListener('keydown', (e) => {
        if (e.key === 'ArrowUp' && direction.y === 0) nextDirection = {x: 0, y: -20};
        if (e.key === 'ArrowDown' && direction.y === 0) nextDirection = {x: 0, y: 20};
        if (e.key === 'ArrowLeft' && direction.x === 0) nextDirection = {x: -20, y: 0};
        if (e.key === 'ArrowRight' && direction.x === 0) nextDirection = {x: 20, y: 0};
    });

    function update() {
        if (!gameRunning) return;

        direction = nextDirection;
        const head = {x: snake[0].x + direction.x, y: snake[0].y + direction.y};

        // Check collisions
        if (head.x < 0 || head.x >= 400 || head.y < 0 || head.y >= 400 || 
            snake.some(s => s.x === head.x && s.y === head.y)) {
            gameRunning = false;
            alert('Game Over! Score: ' + score);
            backToGames();
            return;
        }

        snake.unshift(head);

        if (head.x === food.x && head.y === food.y) {
            score += 10;
            document.getElementById('snakeScore').textContent = 'Score: ' + score;
            food = {x: Math.floor(Math.random() * 20) * 20, y: Math.floor(Math.random() * 20) * 20};
        } else {
            snake.pop();
        }
    }

    function draw() {
        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#00ff00';
        snake.forEach(s => ctx.fillRect(s.x, s.y, 20, 20));

        ctx.fillStyle = '#ff0000';
        ctx.fillRect(food.x, food.y, 20, 20);
    }

    function gameLoop() {
        update();
        draw();
        if (gameRunning) setTimeout(gameLoop, 100);
    }

    gameLoop();
}

// ========== FLAPPY BIRD GAME ==========
function createFlappyGame() {
    return `
        <div style="text-align: center;">
            <h2>🐦 Flappy Bird</h2>
            <p>Click or press Space to flap!</p>
            <canvas id="flappyCanvas" width="400" height="600"></canvas>
            <p id="flappyScore">Score: 0</p>
        </div>
    `;
}

function initializeFlappyGame() {
    const canvas = document.getElementById('flappyCanvas');
    const ctx = canvas.getContext('2d');

    let bird = {x: 50, y: 300, width: 30, height: 30, velocity: 0};
    let pipes = [];
    let score = 0;
    let gameRunning = true;
    let pipeCounter = 0;

    document.addEventListener('keydown', (e) => {
        if (e.code === 'Space') bird.velocity = -10;
    });

    canvas.addEventListener('click', () => {
        bird.velocity = -10;
    });

    function update() {
        if (!gameRunning) return;

        bird.velocity += 0.6;
        bird.y += bird.velocity;

        pipeCounter++;
        if (pipeCounter > 90) {
            const gap = 120;
            const topHeight = Math.random() * (canvas.height - gap - 100) + 50;
            pipes.push({x: canvas.width, width: 60, topHeight: topHeight});
            pipeCounter = 0;
        }

        pipes = pipes.filter(p => p.x > -60);

        pipes.forEach(p => {
            p.x -= 5;
            if (p.x + p.width === 50) score++;
        });

        document.getElementById('flappyScore').textContent = 'Score: ' + score;

        // Collision detection
        if (bird.y < 0 || bird.y + bird.height > canvas.height) {
            gameRunning = false;
        }

        pipes.forEach(p => {
            if (bird.x < p.x + p.width && bird.x + bird.width > p.x) {
                if (bird.y < p.topHeight || bird.y + bird.height > p.topHeight + 120) {
                    gameRunning = false;
                }
            }
        });

        if (!gameRunning) {
            alert('Game Over! Score: ' + score);
            backToGames();
        }
    }

    function draw() {
        ctx.fillStyle = '#87CEEB';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#FFD700';
        ctx.beginPath();
        ctx.arc(bird.x, bird.y, bird.width / 2, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = '#228B22';
        pipes.forEach(p => {
            ctx.fillRect(p.x, 0, p.width, p.topHeight);
            ctx.fillRect(p.x, p.topHeight + 120, p.width, canvas.height);
        });
    }

    function gameLoop() {
        update();
        draw();
        if (gameRunning) requestAnimationFrame(gameLoop);
    }

    gameLoop();
}

// ========== 2048 GAME ==========
function create2048Game() {
    return `
        <div style="text-align: center; color: #fff;">
            <h2>🧩 2048</h2>
            <p>Use arrow keys to move tiles and combine them!</p>
            <p id="score2048">Score: 0</p>
            <div id="board2048" style="display: grid; grid-template-columns: repeat(4, 100px); gap: 10px; margin: 20px auto; width: fit-content; background: #bbada0; padding: 10px; border-radius: 6px;"></div>
            <button onclick="reset2048()" style="padding: 10px 20px; background: #0099ff; color: white; border: none; border-radius: 5px; cursor: pointer;">New Game</button>
        </div>
    `;
}

let board2048 = [];
let score2048 = 0;

function initGame2048() {
    board2048 = Array(16).fill(0);
    score2048 = 0;
    addRandomTile2048();
    addRandomTile2048();
    render2048();
}

function addRandomTile2048() {
    const empty = board2048.map((v, i) => v === 0 ? i : -1).filter(v => v !== -1);
    if (empty.length > 0) {
        const idx = empty[Math.floor(Math.random() * empty.length)];
        board2048[idx] = Math.random() < 0.9 ? 2 : 4;
    }
}

function render2048() {
    const container = document.getElementById('board2048');
    container.innerHTML = '';
    board2048.forEach(val => {
        const tile = document.createElement('div');
        tile.style.width = '100px';
        tile.style.height = '100px';
        tile.style.display = 'flex';
        tile.style.alignItems = 'center';
        tile.style.justifyContent = 'center';
        tile.style.backgroundColor = val ? '#' + (((1 << 24) * Math.random() | 0).toString(16)) : '#cdc1b4';
        tile.style.fontSize = '2em';
        tile.style.fontWeight = 'bold';
        tile.style.color = '#fff';
        tile.style.borderRadius = '3px';
        tile.textContent = val || '';
        container.appendChild(tile);
    });
    document.getElementById('score2048').textContent = 'Score: ' + score2048;
}

function move2048(direction) {
    let moved = false;

    for (let i = 0; i < 4; i++) {
        let row = [];
        if (direction === 'left') {
            row = [board2048[i*4], board2048[i*4+1], board2048[i*4+2], board2048[i*4+3]];
        }

        row = row.filter(v => v !== 0);
        for (let j = 0; j < row.length - 1; j++) {
            if (row[j] === row[j+1]) {
                row[j] *= 2;
                score2048 += row[j];
                row.splice(j+1, 1);
            }
        }
        while (row.length < 4) row.push(0);

        for (let j = 0; j < 4; j++) {
            if (board2048[i*4+j] !== row[j]) moved = true;
            board2048[i*4+j] = row[j];
        }
    }

    if (moved) {
        addRandomTile2048();
        render2048();
    }
}

function reset2048() {
    initGame2048();
}

// ========== TIC TAC TOE GAME ==========
function createTicTacToeGame() {
    return `
        <div style="text-align: center;">
            <h2>⭕ Tic Tac Toe</h2>
            <p>Play against AI (You are X)</p>
            <div id="tictactoeBoard" style="display: grid; grid-template-columns: repeat(3, 100px); gap: 5px; margin: 20px auto; width: fit-content;"></div>
            <button onclick="resetTicTacToe()" style="padding: 10px 20px; background: #0099ff; color: white; border: none; border-radius: 5px; cursor: pointer; margin-top: 20px;">New Game</button>
        </div>
    `;
}

let tictactoeBoard = ['', '', '', '', '', '', '', '', ''];
let tictactoeGameRunning = true;

function initTicTacToe() {
    tictactoeBoard = ['', '', '', '', '', '', '', '', ''];
    tictactoeGameRunning = true;
    renderTicTacToe();
}

function renderTicTacToe() {
    const container = document.getElementById('tictactoeBoard');
    container.innerHTML = '';

    tictactoeBoard.forEach((val, idx) => {
        const cell = document.createElement('button');
        cell.style.width = '100px';
        cell.style.height = '100px';
        cell.style.fontSize = '2em';
        cell.style.fontWeight = 'bold';
        cell.style.background = '#0099ff';
        cell.style.color = '#fff';
        cell.style.border = 'none';
        cell.style.cursor = 'pointer';
        cell.textContent = val;
        cell.onclick = () => playTicTacToe(idx);
        container.appendChild(cell);
    });
}

function playTicTacToe(idx) {
    if (!tictactoeGameRunning || tictactoeBoard[idx]) return;

    tictactoeBoard[idx] = 'X';

    let winner = checkTicTacToeWinner();
    if (winner) {
        alert(winner === 'X' ? 'You Win!' : 'AI Wins!');
        tictactoeGameRunning = false;
        renderTicTacToe();
        return;
    }

    if (tictactoeBoard.every(v => v)) {
        alert('Draw!');
        tictactoeGameRunning = false;
        renderTicTacToe();
        return;
    }

    // AI move
    const empty = tictactoeBoard.map((v, i) => v === '' ? i : -1).filter(v => v !== -1);
    if (empty.length > 0) {
        const idx = empty[Math.floor(Math.random() * empty.length)];
        tictactoeBoard[idx] = 'O';
    }

    winner = checkTicTacToeWinner();
    if (winner) {
        alert(winner === 'X' ? 'You Win!' : 'AI Wins!');
        tictactoeGameRunning = false;
    }

    renderTicTacToe();
}

function checkTicTacToeWinner() {
    const lines = [
        [0, 1, 2], [3, 4, 5], [6, 7, 8],
        [0, 3, 6], [1, 4, 7], [2, 5, 8],
        [0, 4, 8], [2, 4, 6]
    ];

    for (let line of lines) {
        if (tictactoeBoard[line[0]] && 
            tictactoeBoard[line[0]] === tictactoeBoard[line[1]] &&
            tictactoeBoard[line[1]] === tictactoeBoard[line[2]]) {
            return tictactoeBoard[line[0]];
        }
    }
    return null;
}

function resetTicTacToe() {
    initTicTacToe();
}

// ========== BREAKOUT GAME ==========
function createBreakoutGame() {
    return `
        <div style="text-align: center;">
            <h2>🧱 Breakout</h2>
            <p>Move paddle with mouse or arrow keys</p>
            <canvas id="breakoutCanvas" width="500" height="400"></canvas>
            <p id="breakoutScore">Score: 0</p>
        </div>
    `;
}

function initializeBreakoutGame() {
    const canvas = document.getElementById('breakoutCanvas');
    const ctx = canvas.getContext('2d');

    let paddle = {x: canvas.width / 2 - 40, y: canvas.height - 20, width: 80, height: 10};
    let ball = {x: canvas.width / 2, y: canvas.height - 40, radius: 5, vx: 4, vy: -4};
    let bricks = [];
    let score = 0;
    let gameRunning = true;

    // Create bricks
    for (let row = 0; row < 3; row++) {
        for (let col = 0; col < 8; col++) {
            bricks.push({x: col * 60 + 5, y: row * 20 + 5, width: 55, height: 15, active: true});
        }
    }

    document.addEventListener('mousemove', (e) => {
        paddle.x = e.clientX - canvas.offsetLeft - paddle.width / 2;
    });

    document.addEventListener('keydown', (e) => {
        if (e.key === 'ArrowLeft') paddle.x -= 20;
        if (e.key === 'ArrowRight') paddle.x += 20;
    });

    function update() {
        if (!gameRunning) return;

        ball.x += ball.vx;
        ball.y += ball.vy;

        if (ball.x - ball.radius < 0 || ball.x + ball.radius > canvas.width) ball.vx *= -1;
        if (ball.y - ball.radius < 0) ball.vy *= -1;

        if (ball.y + ball.radius > canvas.height) {
            gameRunning = false;
            alert('Game Over! Score: ' + score);
            backToGames();
            return;
        }

        // Paddle collision
        if (ball.y + ball.radius > paddle.y && 
            ball.x > paddle.x && ball.x < paddle.x + paddle.width) {
            ball.vy *= -1;
        }

        // Brick collision
        bricks.forEach(brick => {
            if (brick.active && 
                ball.x > brick.x && ball.x < brick.x + brick.width &&
                ball.y > brick.y && ball.y < brick.y + brick.height) {
                brick.active = false;
                ball.vy *= -1;
                score += 10;
            }
        });

        document.getElementById('breakoutScore').textContent = 'Score: ' + score;

        if (bricks.every(b => !b.active)) {
            alert('You Won! Score: ' + score);
            gameRunning = false;
            backToGames();
        }
    }

    function draw() {
        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#0099ff';
        ctx.fillRect(paddle.x, paddle.y, paddle.width, paddle.height);

        ctx.fillStyle = '#FFD700';
        ctx.beginPath();
        ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
        ctx.fill();

        bricks.forEach(brick => {
            if (brick.active) {
                ctx.fillStyle = '#FF0000';
                ctx.fillRect(brick.x, brick.y, brick.width, brick.height);
            }
        });
    }

    function gameLoop() {
        update();
        draw();
        if (gameRunning) requestAnimationFrame(gameLoop);
    }

    gameLoop();
}

// ========== MEMORY GAME ==========
function createMemoryGame() {
    let cards = [];
    for (let i = 0; i < 8; i++) {
        cards.push(i, i);
    }
    cards = cards.sort(() => Math.random() - 0.5);

    let html = `
        <div style="text-align: center;">
            <h2>🧠 Memory Match</h2>
            <p>Find matching pairs!</p>
            <p id="memoryScore">Matches: 0/8</p>
            <div id="memoryBoard" style="display: grid; grid-template-columns: repeat(4, 80px); gap: 10px; margin: 20px auto; width: fit-content;"></div>
            <button onclick="resetMemory()" style="padding: 10px 20px; background: #0099ff; color: white; border: none; border-radius: 5px; cursor: pointer;">New Game</button>
        </div>
    `;

    window.memoryCards = cards;
    window.memoryFlipped = Array(16).fill(false);
    window.memoryMatched = Array(16).fill(false);
    window.memoryMatches = 0;
    window.memoryLocked = false;

    setTimeout(() => renderMemory(), 100);

    return html;
}

function renderMemory() {
    const container = document.getElementById('memoryBoard');
    if (!container) return;

    container.innerHTML = '';

    window.memoryCards.forEach((card, idx) => {
        const btn = document.createElement('button');
        btn.style.width = '80px';
        btn.style.height = '80px';
        btn.style.fontSize = '2em';
        btn.style.background = window.memoryMatched[idx] ? '#00FF00' : (window.memoryFlipped[idx] ? '#0099ff' : '#666');
        btn.style.color = '#fff';
        btn.style.border = 'none';
        btn.style.cursor = 'pointer';
        btn.style.borderRadius = '5px';
        btn.textContent = window.memoryFlipped[idx] ? '🎮' : '?';
        btn.onclick = () => flipMemoryCard(idx);
        container.appendChild(btn);
    });

    document.getElementById('memoryScore').textContent = 'Matches: ' + window.memoryMatches + '/8';
}

function flipMemoryCard(idx) {
    if (window.memoryLocked || window.memoryFlipped[idx] || window.memoryMatched[idx]) return;

    window.memoryFlipped[idx] = true;
    renderMemory();

    const flipped = window.memoryFlipped.map((v, i) => v ? i : -1).filter(v => v !== -1);

    if (flipped.length === 2) {
        window.memoryLocked = true;

        if (window.memoryCards[flipped[0]] === window.memoryCards[flipped[1]]) {
            window.memoryMatched[flipped[0]] = true;
            window.memoryMatched[flipped[1]] = true;
            window.memoryMatches++;
            window.memoryLocked = false;
            renderMemory();

            if (window.memoryMatches === 8) {
                alert('You Won!');
            }
        } else {
            setTimeout(() => {
                window.memoryFlipped[flipped[0]] = false;
                window.memoryFlipped[flipped[1]] = false;
                window.memoryLocked = false;
                renderMemory();
            }, 1000);
        }
    }
}

function resetMemory() {
    let cards = [];
    for (let i = 0; i < 8; i++) {
        cards.push(i, i);
    }
    window.memoryCards = cards.sort(() => Math.random() - 0.5);
    window.memoryFlipped = Array(16).fill(false);
    window.memoryMatched = Array(16).fill(false);
    window.memoryMatches = 0;
    window.memoryLocked = false;
    renderMemory();
}

// ========== PAC-MAN GAME ==========
function createPacManGame() {
    return `
        <div style="text-align: center;">
            <h2>👾 Pac-Man</h2>
            <p>Use arrow keys to move</p>
            <canvas id="pacmanCanvas" width="400" height="400"></canvas>
            <p id="pacmanScore">Score: 0</p>
        </div>
    `;
}

function initializePacManGame() {
    const canvas = document.getElementById('pacmanCanvas');
    const ctx = canvas.getContext('2d');
    const gridSize = 20;

    let pacman = {x: 10, y: 10};
    let direction = {x: 1, y: 0};
    let nextDirection = {x: 1, y: 0};
    let dots = [];
    let score = 0;
    let gameRunning = true;

    // Create dots
    for (let x = 0; x < 20; x++) {
        for (let y = 0; y < 20; y++) {
            if (Math.random() > 0.2) dots.push({x, y});
        }
    }

    document.addEventListener('keydown', (e) => {
        if (e.key === 'ArrowUp') nextDirection = {x: 0, y: -1};
        if (e.key === 'ArrowDown') nextDirection = {x: 0, y: 1};
        if (e.key === 'ArrowLeft') nextDirection = {x: -1, y: 0};
        if (e.key === 'ArrowRight') nextDirection = {x: 1, y: 0};
    });

    function update() {
        if (!gameRunning) return;

        direction = nextDirection;
        pacman.x += direction.x;
        pacman.y += direction.y;

        // Wrap around
        if (pacman.x < 0) pacman.x = 19;
        if (pacman.x > 19) pacman.x = 0;
        if (pacman.y < 0) pacman.y = 19;
        if (pacman.y > 19) pacman.y = 0;

        // Eat dots
        dots = dots.filter(d => {
            if (d.x === pacman.x && d.y === pacman.y) {
                score += 10;
                return false;
            }
            return true;
        });

        document.getElementById('pacmanScore').textContent = 'Score: ' + score;

        if (dots.length === 0) {
            alert('You Won! Score: ' + score);
            gameRunning = false;
            backToGames();
        }
    }

    function draw() {
        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Draw Pac-man
        ctx.fillStyle = '#FFD700';
        ctx.beginPath();
        ctx.arc(pacman.x * gridSize + gridSize / 2, pacman.y * gridSize + gridSize / 2, gridSize / 2, 0.2, Math.PI * 2 - 0.2);
        ctx.lineTo(pacman.x * gridSize + gridSize / 2, pacman.y * gridSize + gridSize / 2);
        ctx.fill();

        // Draw dots
        ctx.fillStyle = '#FFF';
        dots.forEach(d => {
            ctx.fillRect(d.x * gridSize + 8, d.y * gridSize + 8, 4, 4);
        });
    }

    function gameLoop() {
        update();
        draw();
        if (gameRunning) setTimeout(gameLoop, 200);
    }

    gameLoop();
}

// ========== PONG GAME ==========
function createPongGame() {
    return `
        <div style="text-align: center;">
            <h2>🏓 Pong</h2>
            <p>Move with mouse. Get the ball past opponent!</p>
            <canvas id="pongCanvas" width="600" height="400"></canvas>
            <p id="pongScore">You: 0 | AI: 0</p>
        </div>
    `;
}

function initializePongGame() {
    const canvas = document.getElementById('pongCanvas');
    const ctx = canvas.getContext('2d');

    let playerPaddle = {x: 10, y: canvas.height / 2 - 50, width: 10, height: 100};
    let aiPaddle = {x: canvas.width - 20, y: canvas.height / 2 - 50, width: 10, height: 100};
    let ball = {x: canvas.width / 2, y: canvas.height / 2, radius: 5, vx: 5, vy: 5};
    let playerScore = 0, aiScore = 0;
    let gameRunning = true;

    document.addEventListener('mousemove', (e) => {
        playerPaddle.y = e.clientY - canvas.offsetTop - playerPaddle.height / 2;
    });

    function update() {
        if (!gameRunning) return;

        ball.x += ball.vx;
        ball.y += ball.vy;

        if (ball.y - ball.radius < 0 || ball.y + ball.radius > canvas.height) {
            ball.vy *= -1;
        }

        // Player paddle
        if (ball.x - ball.radius < playerPaddle.x + playerPaddle.width &&
            ball.y > playerPaddle.y && ball.y < playerPaddle.y + playerPaddle.height) {
            ball.vx *= -1;
        }

        // AI paddle
        if (ball.x + ball.radius > aiPaddle.x &&
            ball.y > aiPaddle.y && ball.y < aiPaddle.y + aiPaddle.height) {
            ball.vx *= -1;
        }

        // AI movement
        if (aiPaddle.y + aiPaddle.height / 2 < ball.y) {
            aiPaddle.y += 5;
        } else {
            aiPaddle.y -= 5;
        }

        // Scoring
        if (ball.x < 0) {
            aiScore++;
            ball = {x: canvas.width / 2, y: canvas.height / 2, radius: 5, vx: 5, vy: 5};
        }
        if (ball.x > canvas.width) {
            playerScore++;
            ball = {x: canvas.width / 2, y: canvas.height / 2, radius: 5, vx: -5, vy: 5};
        }

        document.getElementById('pongScore').textContent = `You: ${playerScore} | AI: ${aiScore}`;
    }

    function draw() {
        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#FFF';
        ctx.fillRect(playerPaddle.x, playerPaddle.y, playerPaddle.width, playerPaddle.height);
        ctx.fillRect(aiPaddle.x, aiPaddle.y, aiPaddle.width, aiPaddle.height);

        ctx.beginPath();
        ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
        ctx.fill();
    }

    function gameLoop() {
        update();
        draw();
        if (gameRunning) requestAnimationFrame(gameLoop);
    }

    gameLoop();
}

// ========== GAME INITIALIZER ==========
function initializeGame(gameName) {
    switch(gameName) {
        case 'snake':
            initializeSnakeGame();
            break;
        case 'flappy':
            initializeFlappyGame();
            break;
        case '2048':
            initGame2048();
            document.addEventListener('keydown', (e) => {
                if (['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown'].includes(e.key)) {
                    e.preventDefault();
                    if (e.key === 'ArrowLeft') move2048('left');
                    if (e.key === 'ArrowRight') move2048('right');
                }
            });
            break;
        case 'tictactoe':
            initTicTacToe();
            break;
        case 'breakout':
            initializeBreakoutGame();
            break;
        case 'memory':
            renderMemory();
            break;
        case 'pacman':
            initializePacManGame();
            break;
        case 'pong':
            initializePongGame();
            break;
    }
}

// Initialize home on load
window.addEventListener('DOMContentLoaded', () => {
    showSection('home');
});
