const navBtns = document.querySelectorAll('.nav-btn');
const sections = document.querySelectorAll('.section');

navBtns.forEach(btn => {
    btn.addEventListener('click', () => {
        const target = btn.getAttribute('data-section');
        navigateTo(target);
    });
});

function navigateTo(sectionId) {
    // Update active section
    sections.forEach(section => section.classList.remove('active'));
    document.getElementById(sectionId).classList.add('active');

    // Update active button
    navBtns.forEach(btn => btn.classList.remove('active'));
    document.querySelector(`[data-section="${sectionId}"]`).classList.add('active');

    // Scroll to top
    window.scrollTo(0, 0);
}

// Game Management
function startGame(gameName) {
    const gameContainer = document.getElementById('game-container');
    const gameContent = document.getElementById('game-content');
    gameContent.innerHTML = '';

    switch(gameName) {
        case 'snake':
            loadSnakeGame();
            break;
        case 'flappy':
            loadFlappyGame();
            break;
        case '2048':
            load2048Game();
            break;
        case 'tictactoe':
            loadTicTacToeGame();
            break;
        case 'breakout':
            loadBreakoutGame();
            break;
        case 'memory':
            loadMemoryGame();
            break;
    }

    gameContainer.classList.remove('hidden');
}

function closeGame() {
    document.getElementById('game-container').classList.add('hidden');
    document.getElementById('game-content').innerHTML = '';
}

// ==================== SNAKE GAME ====================
function loadSnakeGame() {
    const canvas = document.createElement('canvas');
    canvas.width = 400;
    canvas.height = 400;
    document.getElementById('game-content').appendChild(canvas);

    const ctx = canvas.getContext('2d');
    const gridSize = 20;
    let snake = [{x: 10, y: 10}];
    let food = {x: 15, y: 15};
    let dx = 1, dy = 0;
    let nextDx = 1, nextDy = 0;
    let score = 0;
    let gameRunning = true;

    document.addEventListener('keydown', (e) => {
        if (e.key === 'ArrowUp' && dy === 0) { nextDx = 0; nextDy = -1; }
        if (e.key === 'ArrowDown' && dy === 0) { nextDx = 0; nextDy = 1; }
        if (e.key === 'ArrowLeft' && dx === 0) { nextDx = -1; nextDy = 0; }
        if (e.key === 'ArrowRight' && dx === 0) { nextDx = 1; nextDy = 0; }
    });

    function update() {
        if (!gameRunning) return;

        dx = nextDx;
        dy = nextDy;

        const head = {x: snake[0].x + dx, y: snake[0].y + dy};

        if (head.x < 0 || head.x >= 20 || head.y < 0 || head.y >= 20) {
            gameRunning = false;
            alert(`Game Over! Score: ${score}`);
            closeGame();
            return;
        }

        for (let segment of snake) {
            if (head.x === segment.x && head.y === segment.y) {
                gameRunning = false;
                alert(`Game Over! Score: ${score}`);
                closeGame();
                return;
            }
        }

        snake.unshift(head);

        if (head.x === food.x && head.y === food.y) {
            score += 10;
            food = {x: Math.floor(Math.random() * 20), y: Math.floor(Math.random() * 20)};
        } else {
            snake.pop();
        }
    }

    function draw() {
        ctx.fillStyle = '#0f0f1e';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#00d4ff';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.strokeStyle = '#00d4ff';
        for (let i = 0; i <= 20; i++) {
            ctx.beginPath();
            ctx.moveTo(i * gridSize, 0);
            ctx.lineTo(i * gridSize, canvas.height);
            ctx.stroke();
            ctx.beginPath();
            ctx.moveTo(0, i * gridSize);
            ctx.lineTo(canvas.width, i * gridSize);
            ctx.stroke();
        }

        ctx.fillStyle = '#00ff00';
        for (let segment of snake) {
            ctx.fillRect(segment.x * gridSize + 1, segment.y * gridSize + 1, gridSize - 2, gridSize - 2);
        }

        ctx.fillStyle = '#ff0000';
        ctx.fillRect(food.x * gridSize + 1, food.y * gridSize + 1, gridSize - 2, gridSize - 2);

        ctx.fillStyle = '#00d4ff';
        ctx.font = 'bold 20px Arial';
        ctx.fillText(`Score: ${score}`, 10, canvas.height + 30);
    }

    function gameLoop() {
        update();
        draw();
        if (gameRunning) setTimeout(gameLoop, 100);
    }

    gameLoop();
}

// ==================== FLAPPY BIRD GAME ====================
function loadFlappyGame() {
    const canvas = document.createElement('canvas');
    canvas.width = 400;
    canvas.height = 600;
    document.getElementById('game-content').appendChild(canvas);

    const ctx = canvas.getContext('2d');
    let bird = {x: 50, y: 300, width: 30, height: 30, velocity: 0, gravity: 0.5, jump: -12};
    let pipes = [];
    let score = 0;
    let gameRunning = true;
    let pipeCounter = 0;

    document.addEventListener('keydown', (e) => {
        if (e.code === 'Space') bird.velocity = bird.jump;
    });
    canvas.addEventListener('click', () => {
        bird.velocity = bird.jump;
    });

    function update() {
        if (!gameRunning) return;

        bird.velocity += bird.gravity;
        bird.y += bird.velocity;

        if (bird.y + bird.height > canvas.height || bird.y < 0) {
            gameRunning = false;
            alert(`Game Over! Score: ${score}`);
            closeGame();
            return;
        }

        pipeCounter++;
        if (pipeCounter > 90) {
            let gap = 150;
            let pipeY = Math.random() * (canvas.height - gap - 100) + 50;
            pipes.push({x: canvas.width, y: pipeY, width: 80, gap: gap});
            pipeCounter = 0;
        }

        for (let i = pipes.length - 1; i >= 0; i--) {
            pipes[i].x -= 6;

            if (pipes[i].x + pipes[i].width < bird.x && !pipes[i].scored) {
                pipes[i].scored = true;
                score++;
            }

            if (bird.x < pipes[i].x + pipes[i].width &&
                bird.x + bird.width > pipes[i].x &&
                (bird.y < pipes[i].y || bird.y + bird.height > pipes[i].y + pipes[i].gap)) {
                gameRunning = false;
                alert(`Game Over! Score: ${score}`);
                closeGame();
                return;
            }

            if (pipes[i].x < -pipes[i].width) pipes.splice(i, 1);
        }
    }

    function draw() {
        ctx.fillStyle = '#87CEEB';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        ctx.fillStyle = '#FFD700';
        ctx.beginPath();
        ctx.arc(bird.x + bird.width / 2, bird.y + bird.height / 2, bird.width / 2, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = '#228B22';
        pipes.forEach(pipe => {
            ctx.fillRect(pipe.x, 0, pipe.width, pipe.y);
            ctx.fillRect(pipe.x, pipe.y + pipe.gap, pipe.width, canvas.height - pipe.y - pipe.gap);
        });

        ctx.fillStyle = '#00d4ff';
        ctx.font = 'bold 28px Arial';
        ctx.fillText(`Score: ${score}`, 10, 40);
    }

    function gameLoop() {
        update();
        draw();
