    padding: 30px 20px;
    text-align: center;
    box-shadow: 0 8px 32px rgba(0, 212, 255, 0.3);
}

header h1 {
    font-size: 48px;
    margin-bottom: 10px;
    text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);
}

.subtitle {
    font-size: 18px;
    opacity: 0.9;
}

/* ==================== NAVBAR ==================== */

.navbar {
    display: flex;
    justify-content: center;
    gap: 20px;
    padding: 20px;
    background: rgba(0, 0, 0, 0.3);
    border-bottom: 2px solid #00d4ff;
    flex-wrap: wrap;
}

.nav-btn {
    padding: 12px 24px;
    background: #1a1a2e;
    color: #00d4ff;
    border: 2px solid #00d4ff;
    border-radius: 8px;
    cursor: pointer;
    font-size: 16px;
    font-weight: bold;
    transition: all 0.3s ease;
}

.nav-btn:hover {
    background: #00d4ff;
    color: #0f0f1e;
    transform: translateY(-2px);
    box-shadow: 0 8px 16px rgba(0, 212, 255, 0.4);
}

.nav-btn.active {
    background: #00d4ff;
    color: #0f0f1e;
}

/* ==================== CONTAINER ==================== */

.container {
    max-width: 1200px;
    margin: 40px auto;
    padding: 0 20px;
}

