    margin-bottom: 40px;
}

.welcome-box h2 {
    font-size: 32px;
    margin-bottom: 20px;
    color: #00d4ff;
}

.welcome-box p {
    font-size: 18px;
    margin-bottom: 30px;
    opacity: 0.9;
}

.home-options {
    display: grid;
