    gap: 30px;
    margin-top: 30px;
}

.option-card {
    background: #1a1a2e;
    border: 2px solid #00d4ff;
    border-radius: 12px;
    padding: 30px;
    transition: all 0.3s ease;
}

.option-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 32px rgba(0, 212, 255, 0.3);
