.game-link:hover {
    background: linear-gradient(135deg, #00d4ff 0%, #0084ff 100%);
    color: #0f0f1e;
    transform: translateY(-3px);
    box-shadow: 0 8px 20px rgba(0, 212, 255, 0.4);
