    border: 2px solid #00d4ff;
    border-radius: 12px;
    padding: 25px;
}

.category h3 {
    font-size: 22px;
    margin-bottom: 20px;
    color: #00d4ff;
    text-shadow: 0 0 10px rgba(0, 212, 255, 0.2);
}

.game-links {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px;
}

.game-link {
    display: inline-block;
    padding: 12px 20px;
    background: linear-gradient(135deg, #1a1a2e 0%, #2a2a4e 100%);
    color: #00d4ff;
    text-decoration: none;
    border: 2px solid #00d4ff;
    border-radius: 8px;
    transition: all 0.3s ease;
    font-weight: bold;
    text-align: center;
}

.game-link:hover {
    background: linear-gradient(135deg, #00d4ff 0%, #0084ff 100%);
    color: #0f0f1e;
    transform: translateY(-3px);
    box-shadow: 0 8px 20px rgba(0, 212, 255, 0.4);
}

/* ==================== GAME CONTAINER (MODAL) ==================== */

.game-container {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.8);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    backdrop-filter: blur(5px);
}

.game-container.hidden {
    display: none;
}

.game-modal {
    background: #0f0f1e;
    border: 3px solid #00d4ff;
    border-radius: 16px;
    padding: 30px;
    max-width: 90%;
    max-height: 90%;
    overflow: auto;
    position: relative;
    box-shadow: 0 0 40px rgba(0, 212, 255, 0.5);
}

.close-btn {
    position: absolute;
    top: 15px;
    right: 15px;
    background: #ff0000;
    color: white;
    border: none;
    width: 40px;
    height: 40px;
    border-radius: 50%;
    font-size: 24px;
    cursor: pointer;
    transition: all 0.3s ease;
    z-index: 1001;
}

.close-btn:hover {
    background: #ff3333;
    transform: scale(1.1);
}

#game-content {
    text-align: center;
    color: #e0e0e0;
}

#game-content canvas {
    border: 2px solid #00d4ff;
    border-radius: 8px;
    background: #000;
    margin: 20px auto;
    display: block;
}

/* ==================== FOOTER ==================== */

footer {
    background: rgba(0, 0, 0, 0.5);
    border-top: 2px solid #00d4ff;
    padding: 30px;
    text-align: center;
    color: #a0a0a0;
    margin-top: 60px;
}

/* ==================== RESPONSIVE DESIGN ==================== */

@media (max-width: 768px) {
    header h1 {
        font-size: 32px;
    }

    .subtitle {
        font-size: 14px;
    }

    .navbar {
        gap: 10px;
    }

    .nav-btn {
        padding: 10px 16px;
        font-size: 14px;
    }

    .section-title {
        font-size: 24px;
    }

    .games-grid,
    .game-links {
        grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    }

    .welcome-box {
        padding: 20px;
    }

    .home-options {
        grid-template-columns: 1fr;
    }

    .game-modal {
        padding: 20px;
        max-width: 95%;
    }

    .game-link {
        padding: 10px 16px;
        font-size: 14px;
    }
}

@media (max-width: 480px) {
    header {
        padding: 20px 10px;
    }

    header h1 {
        font-size: 24px;
    }

    .container {
        margin: 20px auto;
    }

    .games-grid,
    .game-links {
        grid-template-columns: 1fr;
    }

    .category {
        padding: 15px;
    }

    .nav-btn {
        padding: 8px 12px;
        font-size: 12px;
    }
}

/* ==================== ANIMATIONS ==================== */

@keyframes pulse {
    0%, 100% {
        opacity: 1;
    }
    50% {
        opacity: 0.7;
    }
}

.game-card:active {
    animation: pulse 0.5s ease-in-out;
}
