{"content": "/* ==================== GLOBAL STYLES ==================== */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: #333;
    min-height: 100vh;
    padding: 20px;
}

.weather-container {
    max-width: 1200px;
    margin: 0 auto;
    background: white;
    border-radius: 20px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    overflow: hidden;
}

/* ==================== HEADER ==================== */

.weather-header {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    padding: 40px 20px;
    text-align: center;
}

.weather-header h1 {
    font-size: 48px;
    margin-bottom: 10px;
    text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.2);
}

.tagline {
    font-size: 18px;
    opacity: 0.9;
}

/* ==================== NAVIGATION ==================== */

.weather-nav {
    display: flex;
    justify-content: center;
    gap: 10px;
    padding: 20px;
    background: #f8f9fa;
    border-bottom: 2px solid #e9ecef;
    flex-wrap: wrap;
}

.nav-btn {
    padding: 10px 24px;
    background: white;
    color: #667eea;
    border: 2px solid #667eea;
    border-radius: 25px;
    cursor: pointer;
    font-weight: bold;
    font-size: 14px;
    transition: all 0.3s ease;
}

.nav-btn:hover {
    background: #667eea;
    color: white;
    transform: translateY(-2px);
}

.nav-btn.active {
    background: #667eea;
    color: white;
}

/* ==================== SEARCH CONTAINER ==================== */

.search-container {
    display: flex;
    gap: 10px;
    padding: 20px;
    background: #f8f9fa;
    justify-content: center;
    flex-wrap: wrap;
}

.search-input {
    flex: 1;
    min-width: 200px;
    max-width: 400px;
    padding: 12px 20px;
    border: 2px solid #667eea;
    border-radius: 25px;
    font-size: 16px;
    transition: all 0.3s ease;
}

.search-input:focus {
    outline: none;
    border-color: #764ba2;
    box-shadow: 0 0 10px rgba(102, 126, 234, 0.3);
}

.search-btn,
.location-btn {
    padding: 12px 24px;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    border: none;
    border-radius: 25px;
    cursor: pointer;
    font-weight: bold;
    font-size: 14px;
    transition: all 0.3s ease;
}

.search-btn:hover,
.location-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 16px rgba(102, 126, 234, 0.3);
}

/* ==================== ERROR MESSAGE ==================== */

.error-message {
    padding: 15px 20px;
    margin: 10px 20px 0;
    background: #f8d7da;
    color: #721c24;
    border: 1px solid #f5c6cb;
    border-radius: 8px;
    display: none;
}

.error-message.show {
    display: block;
    animation: slideDown 0.3s ease;
}

@keyframes slideDown {
    from {
        opacity: 0;
        transform: translateY(-10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* ==================== LOADING SPINNER ==================== */

.loading-spinner {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 60px 20px;
    gap: 20px;
}

.loading-spinner.hidden {
    display: none;
}

.spinner {
    width: 50px;
    height: 50px;
    border: 4px solid #f3f3f3;
    border-top: 4px solid #667eea;
    border-radius: 50%;
    animation: spin 1s linear infinite;
}

@keyframes spin {
    0% {
        transform: rotate(0deg);
    }
    100% {
        transform: rotate(360deg);
    }
}

/* ==================== SECTIONS ==================== */

.section {
    display: none;
    animation: fadeIn 0.5s ease-in;
}

.section.active {
    display: block;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* ==================== CURRENT WEATHER SECTION ==================== */

.current-weather {
    padding: 40px 20px;
}

.city-info {
    text-align: center;
    margin-bottom: 30px;
}

.city-info h2 {
    font-size: 32px;
    color: #333;
    margin-bottom: 5px;
}

.city-info p {
    font-size: 14px;
    color: #666;
}

.weather-main {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 40px;
    margin-bottom: 50px;
    flex-wrap: wrap;
}

.temp-display {
    display: flex;
    align-items: center;
    gap: 30px;
}

.temp {
    font-size: 72px;
    font-weight: bold;
    color: #667eea;
}

.weather-icon-large {
    width: 80px;
    height: 80px;
}

.weather-description {
    text-align: center;
}

.condition {
    font-size: 24px;
    color: #333;
    margin-bottom: 10px;
    text-transform: capitalize;
}

.feels-like {
    font-size: 16px;
    color: #666;
}

/* ==================== WEATHER DETAILS ==================== */

.weather-details {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 20px;
}

.detail-card {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    padding: 20px;
    border-radius: 12px;
    display: flex;
    flex-direction: column;
    gap: 10px;
    text-align: center;
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.2);
}

.detail-card .label {
    font-size: 14px;
    opacity: 0.9;
}

.detail-card .value {
    font-size: 20px;
    font-weight: bold;
}

/* ==================== FORECAST SECTION ==================== */

.forecast-container,
.hourly-forecast-container {
    padding: 40px 20px;
}

.section-title {
    text-align: center;
    font-size: 28px;
    margin-bottom: 30px;
    color: #333;
}

.forecast-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    gap: 20px;
}

.forecast-card {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    padding: 20px;
    border-radius: 12px;
    text-align: center;
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.2);
    transition: all 0.3s ease;
}

.forecast-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 20px rgba(102, 126, 234, 0.3);
}

.forecast-day {
    font-size: 14px;
    margin-bottom: 12px;
    font-weight: bold;
}

.forecast-icon {
    width: 50px;
    height: 50px;
    margin: 10px auto;
}

.forecast-temp {
    font-size: 18px;
    font-weight: bold;
    margin: 10px 0;
}

.forecast-condition {
    font-size: 12px;
    opacity: 0.9;
    text-transform: capitalize;
}

/* ==================== HOURLY FORECAST ==================== */

.hourly-forecast {
    display: flex;
    gap: 15px;
    overflow-x: auto;
    padding: 20px 0;
    padding-bottom: 10px;
}

.hourly-card {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    padding: 15px;
    border-radius: 12px;
    text-align: center;
    min-width: 100px;
    flex-shrink: 0;
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.2);
}

.hourly-time {
    font-size: 12px;
    font-weight: bold;
    margin-bottom: 8px;
}

.hourly-icon {
    width: 40px;
    height: 40px;
    margin: 8px auto;
}

.hourly-temp {
    font-size: 16px;
    font-weight: bold;
}

/* ==================== SETTINGS SECTION ==================== */

.settings-container {
    padding: 40px 20px;
}

.settings-box {
    background: #f8f9fa;
    padding: 25px;
    border-radius: 12px;
    margin-bottom: 20px;
    border: 1px solid #e9ecef;
}

.settings-box h3 {
