/* ==================== FOOTER ==================== */

.weather-footer {
    background: #f8f9fa;
    padding: 20px;
    text-align: center;
    color: #666;
    border-top: 1px solid #e9ecef;
    font-size: 14px;
}

/* ==================== RESPONSIVE DESIGN ==================== */

@media (max-width: 768px) {
    .weather-header h1 {
        font-size: 32px;
    }

    .temp {
        font-size: 48px;
    }

