{"content": "// ==================== WEATHER DASHBOARD SCRIPT ====================

// API Configuration (Open-Meteo - Free, No API Key Required)
const API_BASE = 'https://api.open-meteo.com/v1/forecast';
const GEOCODING_API = 'https://geocoding-api.open-meteo.com/v1/search';

// State Management
let currentWeatherData = null;
let currentForecastData = null;
let currentLocation = null;
let temperatureUnit = 'celsius';
let windSpeedUnit = 'kmh';

// DOM Elements
const searchInput = document.getElementById('cityInput');
const searchBtn = document.getElementById('searchBtn');
const locationBtn = document.getElementById('locationBtn');
const errorMessage = document.getElementById('errorMessage');
const loadingSpinner = document.getElementById('loadingSpinner');
const navBtns = document.querySelectorAll('.nav-btn');
const sections = document.querySelectorAll('.section');
const unitRadios = document.querySelectorAll('input[name="unit"]');
const windUnitRadios = document.querySelectorAll('input[name="windUnit"]');
const defaultCityInput = document.getElementById('defaultCity');
const saveDefaultBtn = document.getElementById('saveDefaultBtn');

// ==================== EVENT LISTENERS ====================

searchBtn.addEventListener('click', () => {
    const city = searchInput.value.trim();
    if (city) searchWeatherByCity(city);
});

searchInput.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') {
        const city = searchInput.value.trim();
        if (city) searchWeatherByCity(city);
    }
});

locationBtn.addEventListener('click', getWeatherByLocation);

navBtns.forEach(btn => {
    btn.addEventListener('click', () => {
        const target = btn.getAttribute('data-section');
        switchSection(target);
        navBtns.forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
    });
});

unitRadios.forEach(radio => {
    radio.addEventListener('change', (e) => {
        temperatureUnit = e.target.value;
        localStorage.setItem('temperatureUnit', temperatureUnit);
        updateWeatherDisplay();
    });
});

windUnitRadios.forEach(radio => {
    radio.addEventListener('change', (e) => {
        windSpeedUnit = e.target.value;
        localStorage.setItem('windSpeedUnit', windSpeedUnit);
        updateWeatherDisplay();
    });
});

saveDefaultBtn.addEventListener('click', () => {
    const defaultCity = defaultCityInput.value.trim();
    if (defaultCity) {
        localStorage.setItem('defaultCity', defaultCity);
        alert('Default city saved!');
    }
});

// ==================== INITIALIZATION ====================

function init() {
    // Load saved preferences
    const savedUnit = localStorage.getItem('temperatureUnit') || 'celsius';
    const savedWindUnit = localStorage.getItem('windSpeedUnit') || 'kmh';
    temperatureUnit = savedUnit;
    windSpeedUnit = savedWindUnit;

    document.querySelector(`input[value="${savedUnit}"]`).checked = true;
    document.querySelector(`input[value="${savedWindUnit}"]`).checked = true;

    const savedDefaultCity = localStorage.getItem('defaultCity');
    if (savedDefaultCity) defaultCityInput.value = savedDefaultCity;

    // Load weather for default city or London
    const cityToLoad = savedDefaultCity || 'London';
    searchWeatherByCity(cityToLoad);
}

// ==================== SECTION SWITCHING ====================

function switchSection(sectionId) {
    sections.forEach(section => section.classList.remove('active'));
    document.getElementById(sectionId).classList.add('active');
}

// ==================== ERROR HANDLING ====================

function showError(message) {
    errorMessage.textContent = message;
    errorMessage.classList.add('show');
    setTimeout(() => {
        errorMessage.classList.remove('show');
    }, 5000);
}

function hideError() {
    errorMessage.classList.remove('show');
}

// ==================== LOADING STATE ====================

function showLoading() {
    loadingSpinner.classList.remove('hidden');
}

function hideLoading() {
    loadingSpinner.classList.add('hidden');
}

// ==================== GEOCODING - GET COORDINATES FROM CITY NAME ====================

async function geocodeCity(cityName) {
    try {
        const response = await fetch(
            `${GEOCODING_API}?name=${encodeURIComponent(cityName)}&count=1&language=en&format=json`
        );
        const data = await response.json();

        if (data.results && data.results.length > 0) {
            const result = data.results[0];
            return {
                name: result.name,
                country: result.country,
                latitude: result.latitude,
                longitude: result.longitude,
                timezone: result.timezone
            };
        } else {
            throw new Error(`City "${cityName}" not found`);
        }
    } catch (error) {
        showError(error.message);
        hideLoading();
        return null;
    }
}

// ==================== WEATHER BY CITY ====================

async function searchWeatherByCity(cityName) {
    showLoading();
    hideError();

    const location = await geocodeCity(cityName);
    if (!location) return;

    currentLocation = location;
    await fetchWeatherData(location.latitude, location.longitude);
}

// ==================== GEOLOCATION - GET USER'S LOCATION ====================

function getWeatherByLocation() {
    if (!navigator.geolocation) {
        showError('Geolocation is not supported by your browser');
        return;
    }

    showLoading();
    navigator.geolocation.getCurrentPosition(
        (position) => {
            const { latitude, longitude } = position.coords;
            fetchWeatherData(latitude, longitude, true);
        },
        (error) => {
            hideLoading();
            showError(`Geolocation error: ${error.message}`);
        }
    );
}

// ==================== FETCH WEATHER DATA ====================

async function fetchWeatherData(latitude, longitude, useGeolocation = false) {
    try {
        showLoading();
        hideError();

        const params = new URLSearchParams({
            latitude: latitude,
            longitude: longitude,
            current: 'temperature_2m,relative_humidity_2m,apparent_temperature,weather_code,wind_speed_10m,pressure_msl,visibility,dew_point_2m',
            hourly: 'temperature_2m,weather_code,wind_speed_10m',
            daily: 'weather_code,temperature_2m_max,temperature_2m_min,precipitation_sum,wind_speed_10m_max,uv_index_max',
            temperature_unit: temperatureUnit === 'celsius' ? 'celsius' : 'fahrenheit',
            wind_speed_unit: windSpeedUnit === 'kmh' ? 'kmh' : windSpeedUnit === 'mph' ? 'mph' : 'ms',
            timezone: 'auto'
        });

        const response = await fetch(`${API_BASE}?${params}`);
        const data = await response.json();

        if (data.error) {
            throw new Error(data.error_description);
        }

        currentWeatherData = data.current;
        currentForecastData = data;

        // If using geolocation, reverse geocode to get city name
        if (useGeolocation) {
            currentLocation = {
                latitude: latitude,
                longitude: longitude,
                timezone: data.timezone
            };
        }

        updateWeatherDisplay();
        hideLoading();
    } catch (error) {
        hideLoading();
        showError(`Failed to fetch weather: ${error.message}`);
    }
}

// ==================== WEATHER CODE TO DESCRIPTION ====================

function getWeatherDescription(weatherCode) {
    const weatherCodes = {
        0: 'Clear sky',
        1: 'Mainly clear',
        2: 'Partly cloudy',
        3: 'Overcast',
        45: 'Foggy',
        48: 'Depositing rime fog',
        51: 'Drizzle',
        53: 'Moderate drizzle',
        55: 'Heavy drizzle',
        61: 'Slight rain',
        63: 'Moderate rain',
        65: 'Heavy rain',
        71: 'Slight snow',
        73: 'Moderate snow',
        75: 'Heavy snow',
        77: 'Snow grains',
        80: 'Slight rain showers',
        81: 'Moderate rain showers',
        82: 'Violent rain showers',
        85: 'Slight snow showers',
        86: 'Heavy snow showers',
        95: 'Thunderstorm',
        96: 'Thunderstorm with slight hail',
        99: 'Thunderstorm with heavy hail'
    };
    return weatherCodes[weatherCode] || 'Unknown';
}

// ==================== WEATHER CODE TO ICON ====================

function getWeatherIcon(weatherCode) {
    const iconMap = {
        0: '☀️',
        1: '🌤️',
        2: '⛅',
        3: '☁️',
        45: '🌫️',
        48: '🌫️',
        51: '🌧️',
        53: '🌧️',
        55: '⛈️',
        61: '🌧️',
        63: '🌧️',
        65: '⛈️',
        71: '❄️',
        73: '❄️',
        75: '❄️',
        77: '❄️',
        80: '🌧️',
        81: '⛈️',
        82: '⛈️',
        85: '❄️',
        86: '❄️',
        95: '⛈️',
        96: '⛈️',
        99: '⛈️'
    };
    return iconMap[weatherCode] || '🌡️';
}

// ==================== UPDATE WEATHER DISPLAY ====================

function updateWeatherDisplay() {
    if (!currentWeatherData) return;

    const data = currentWeatherData;
    const forecastData = currentForecastData;

    // Update city info
    document.getElementById('cityName').textContent = currentLocation.name || 'Unknown Location';
    document.getElementById('dateTime').textContent = new Date().toLocaleDateString('en-US', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    });

    // Update temperature and condition
    const tempUnit = temperatureUnit === 'celsius' ? '°C' : '°F';
    document.getElementById('temperature').textContent = `${Math.round(data.temperature_2m)}${tempUnit}`;
    document.getElementById('feelsLike').textContent = `Feels like ${Math.round(data.apparent_temperature)}${tempUnit}`;
    document.getElementById('condition').textContent = getWeatherDescription(data.weather_code);

    // Update weather icon
    const iconEmoji = getWeatherIcon(data.weather_code);
    const weatherIcon = document.getElementById('weatherIcon');
    weatherIcon.textContent = iconEmoji;
    weatherIcon.style.fontSize = '60px';

    // Update details
    const windUnit = windSpeedUnit === 'kmh' ? 'km/h' : windSpeedUnit === 'mph' ? 'mph' : 'm/s';
    document.getElementById('windSpeed').textContent = `${Math.round(data.wind_speed_10m)} ${windUnit}`;
    document.getElementById('humidity').textContent = `${data.relative_humidity_2m}%`;
    document.getElementById('pressure').textContent = `${Math.round(data.pressure_msl)} mb`;
    document.getElementById('visibility').textContent = `${(data.visibility / 1000).toFixed(1)} km`;
    document.getElementById('dewPoint').textContent = `${Math.round(data.dew_point_2m)}${tempUnit}`;

    // Calculate UV Index (placeholder)
    document.getElementById('uvIndex').textContent = data.weather_code < 3 ? 'High' : 'Low';

    // Update last update time
    document.getElementById('lastUpdate').textContent = new Date().toLocaleTimeString();

    // Update forecasts
    updateForecastDisplay();
}

// ==================== UPDATE FORECAST DISPLAY ====================

function updateForecastDisplay() {
    if (!currentForecastData) return;

    const daily = currentForecastData.daily;
    const hourly = currentForecastData.hourly;
    const tempUnit = temperatureUnit === 'celsius' ? '°C' : '°F';

    // 7-Day Forecast
    const forecastGrid = document.getElementById('forecastGrid');
    forecastGrid.innerHTML = '';

    for (let i = 0; i < 7; i++) {
        const date = new Date(daily.time[i]);
        const day = date.toLocaleDateString('en-US', { weekday: 'short' });
        const maxTemp = Math.round(daily.temperature_2m_max[i]);
        const minTemp = Math.round(daily.temperature_2m_min[i]);
        const weatherCode = daily.weather_code[i];
        const icon = getWeatherIcon(weatherCode);
        const condition = getWeatherDescription(weatherCode);

        const card = document.createElement('div');
        card.className = 'forecast-card';
        card.innerHTML = `
            <div class="forecast-day">${day}</div>
            <div class="forecast-icon">${icon}</div>
            <div class="forecast-temp">${maxTemp}° / ${minTemp}°</div>
            <div class="forecast-condition">${condition}</div>
        `;
        forecastGrid.appendChild(card);
    }

    // 24-Hour Forecast
    const hourlyForecast = document.getElementById('hourlyForecast');
    hourlyForecast.innerHTML = '';

    for (let i = 0; i < 24; i++) {
        const timeIndex = i;
        const time = hourly.time[timeIndex];
        const date = new Date(time);
        const hour = date.getHours();
        const temp = Math.round(hourly.temperature_2m[timeIndex]);
        const weatherCode = hourly.weather_code[timeIndex];
        const icon = getWeatherIcon(weatherCode);

        const card = document.createElement('div');
        card.className = 'hourly-card';
        card.innerHTML = `
            <div class="hourly-time">${hour}:00</div>
            <div class="hourly-icon">${icon}</div>
            <div class="hourly-temp">${temp}${tempUnit.charAt(0)}</div>
        `;
        hourlyForecast.appendChild(card);
    }
}

// ==================== INITIALIZE APP ====================

window.addEventListener('load', init);
