{"content": "/* Weather Dashboard Styles */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: #333;
    min-height: 100vh;
    padding: 20px;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
}

/* Header */
header {
    background: rgba(255, 255, 255, 0.95);
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 30px;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
}

header h1 {
    color: #667eea;
    font-size: 32px;
    margin-bottom: 20px;
}

.search-box {
    display: flex;
    gap: 10px;
    margin-bottom: 15px;
}

#cityInput {
    flex: 1;
    padding: 12px 15px;
    border: 2px solid #667eea;
    border-radius: 8px;
    font-size: 16px;
    transition: all 0.3s ease;
}

#cityInput:focus {
    outline: none;
    border-color: #764ba2;
    box-shadow: 0 0 10px rgba(102, 126, 234, 0.3);
}

#searchBtn, #locationBtn, #settingsToggle {
    padding: 12px 20px;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    border: none;
    border-radius: 8px;
    cursor: pointer;
    font-weight: bold;
    transition: all 0.3s ease;
}

#searchBtn:hover, #locationBtn:hover, #settingsToggle:hover {
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);
}

#searchBtn:active, #locationBtn:active, #settingsToggle:active {
    transform: translateY(0);
}

.button-group {
    display: flex;
    gap: 10px;
}

/* Weather Display */
.weather-container {
    display: grid;
    grid-template-columns: 1fr;
    gap: 25px;
}

/* Current Weather */
#currentWeather {
    background: rgba(255, 255, 255, 0.95);
    border-radius: 15px;
    padding: 30px;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
}

.weather-header-info {
    text-align: center;
    margin-bottom: 25px;
}

.weather-location {
    font-size: 24px;
    font-weight: bold;
    color: #667eea;
    margin-bottom: 5px;
}

.weather-description {
    font-size: 18px;
    color: #666;
    margin-bottom: 15px;
    text-transform: capitalize;
}

.temperature-display {
    font-size: 64px;
    font-weight: bold;
    color: #764ba2;
    margin: 15px 0;
}

.temp-feels-like {
    font-size: 16px;
    color: #888;
}

.weather-details {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    gap: 15px;
}

.detail-item {
    background: linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%);
    padding: 15px;
    border-radius: 10px;
    border-left: 4px solid #667eea;
    text-align: center;
}

.detail-label {
    font-size: 12px;
    color: #888;
    text-transform: uppercase;
    margin-bottom: 8px;
    font-weight: 600;
}

.detail-value {
    font-size: 20px;
    font-weight: bold;
    color: #764ba2;
}

/* Hourly Forecast */
#hourlyForecast {
    background: rgba(255, 255, 255, 0.95);
    border-radius: 15px;
    padding: 30px;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
}

#hourlyForecast h2 {
    color: #667eea;
    margin-bottom: 20px;
    font-size: 22px;
}

.hourly-container {
    display: flex;
    gap: 12px;
    overflow-x: auto;
    padding-bottom: 15px;
}

.hourly-card {
    background: linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%);
    border: 2px solid #667eea;
    border-radius: 10px;
    padding: 15px;
    min-width: 90px;
    text-align: center;
    transition: all 0.3s ease;
}

.hourly-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 20px rgba(102, 126, 234, 0.3);
}

.hourly-time {
    font-size: 12px;
    color: #888;
    font-weight: 600;
    margin-bottom: 8px;
}

.hourly-icon {
    font-size: 32px;
    margin: 8px 0;
}

.hourly-temp {
    font-size: 16px;
    font-weight: bold;
    color: #764ba2;
}

/* Daily Forecast */
#dailyForecast {
    background: rgba(255, 255, 255, 0.95);
    border-radius: 15px;
    padding: 30px;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
}

#dailyForecast h2 {
    color: #667eea;
    margin-bottom: 20px;
    font-size: 22px;
}

.daily-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    gap: 15px;
}

.daily-card {
    background: linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%);
    border: 2px solid #667eea;
    border-radius: 10px;
    padding: 15px;
    text-align: center;
    transition: all 0.3s ease;
}

.daily-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 20px rgba(102, 126, 234, 0.3);
}

.daily-date {
    font-size: 14px;
    color: #888;
    font-weight: 600;
    margin-bottom: 10px;
}

.daily-icon {
    font-size: 40px;
    margin: 10px 0;
}

.daily-desc {
    font-size: 12px;
    color: #666;
    text-transform: capitalize;
    margin-bottom: 10px;
    min-height: 24px;
}

.daily-temps {
    display: flex;
    justify-content: space-around;
    gap: 10px;
}

.daily-high {
    font-size: 16px;
    font-weight: bold;
    color: #764ba2;
}

.daily-low {
    font-size: 14px;
    color: #aaa;
    font-weight: 600;
}

/* Settings Panel */
.settings-panel {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    backdrop-filter: blur(5px);
}

.settings-panel.hidden {
    display: none;
}

.settings-content {
    background: white;
    border-radius: 15px;
    padding: 30px;
    max-width: 400px;
    width: 90%;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
}

.settings-content h2 {
    color: #667eea;
    margin-bottom: 20px;
    font-size: 22px;
}

.setting-item {
    margin-bottom: 20px;
}

.setting-item label {
    display: block;
    color: #333;
    font-weight: 600;
    margin-bottom: 8px;
    font-size: 14px;
}

.setting-item select,
.setting-item input {
    width: 100%;
    padding: 10px;
    border: 2px solid #667eea;
    border-radius: 8px;
    font-size: 14px;
    transition: all 0.3s ease;
}

.setting-item select:focus,
.setting-item input:focus {
    outline: none;
    border-color: #764ba2;
    box-shadow: 0 0 10px rgba(102, 126, 234, 0.3);
}

.settings-buttons {
    display: flex;
    gap: 10px;
    margin-top: 25px;
}

#saveDefaultBtn, #closeSettings {
    flex: 1;
    padding: 12px;
    border: none;
    border-radius: 8px;
    cursor: pointer;
    font-weight: bold;
    transition: all 0.3s ease;
}

#saveDefaultBtn {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
}

#saveDefaultBtn:hover {
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);
}

#closeSettings {
    background: #f0f0f0;
    color: #333;
    border: 2px solid #ddd;
}

#closeSettings:hover {
    background: #e0e0e0;
}

/* Responsive Design */
@media (max-width: 768px) {
    header h1 {
        font-size: 24px;
    }

    .search-box {
        flex-direction: column;
    }

    .button-group {
        flex-direction: column;
    }

    #searchBtn, #locationBtn, #settingsToggle {
        width: 100%;
    }

    .temperature-display {
        font-size: 48px;
    }

    .weather-details {
        grid-template-columns: repeat(2, 1fr);
    }

    .daily-grid {
        grid-template-columns: repeat(auto-fit, minmax(100px, 1fr));
    }

    #currentWeather, #hourlyForecast, #dailyForecast {
        padding: 20px;
    }
}

@media (max-width: 480px) {
    body {
        padding: 10px;
    }

    header {
        padding: 15px;
        margin-bottom: 20px;
    }

    header h1 {
        font-size: 20px;
        margin-bottom: 15px;
    }

    #currentWeather, #hourlyForecast, #dailyForecast {
        padding: 15px;
        border-radius: 12px;
    }

    .temperature-display {
        font-size: 40px;
    }

    .weather-details {
        grid-template-columns: 1fr;
    }

    .daily-grid {
        grid-template-columns: 1fr;
    }

    .hourly-card {
        min-width: 70px;
        padding: 10px;
    }

    .settings-content {
        padding: 20px;
    }
}
