{"content": "/* ==================== GLOBAL STYLES ==================== */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    padding: 20px;
    color: #e0e0e0;
}

/* ==================== CONTAINER ==================== */

.clock-container {
    max-width: 1400px;
    margin: 0 auto;
}

/* ==================== HEADER ==================== */

header {
    text-align: center;
    margin-bottom: 40px;
    animation: slideDown 0.6s ease-out;
}

@keyframes slideDown {
    from {
        opacity: 0;
        transform: translateY(-30px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

header h1 {
    font-size: 48px;
    margin-bottom: 10px;
    text-shadow: 0 2px 10px rgba(0, 0, 0, 0.3);
    color: #fff;
}

.subtitle {
    font-size: 18px;
    opacity: 0.9;
    color: rgba(255, 255, 255, 0.9);
}

/* ==================== CONTROLS ==================== */

.controls {
    display: flex;
    justify-content: center;
    gap: 30px;
    margin-bottom: 40px;
    flex-wrap: wrap;
    animation: slideUp 0.6s ease-out 0.2s backwards;
}

@keyframes slideUp {
    from {
        opacity: 0;
        transform: translateY(30px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.search-box {
    display: flex;
    gap: 10px;
    background: rgba(0, 0, 0, 0.3);
    padding: 15px;
    border-radius: 12px;
    border: 2px solid rgba(255, 255, 255, 0.3);
}

.search-box input {
    padding: 10px 15px;
    border: none;
    border-radius: 8px;
    background: rgba(255, 255, 255, 0.1);
    color: #fff;
    font-size: 16px;
    width: 250px;
    transition: all 0.3s ease;
}

.search-box input::placeholder {
    color: rgba(255, 255, 255, 0.6);
}

.search-box input:focus {
    outline: none;
    background: rgba(255, 255, 255, 0.2);
    box-shadow: 0 0 15px rgba(255, 255, 255, 0.3);
}

.search-box button,
#addTimezoneBtn {
    padding: 10px 20px;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: #fff;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-radius: 8px;
    cursor: pointer;
    font-weight: bold;
    font-size: 14px;
    transition: all 0.3s ease;
}

.search-box button:hover,
#addTimezoneBtn:hover {
    background: linear-gradient(135deg, #764ba2 0%, #667eea 100%);
    border-color: rgba(255, 255, 255, 0.6);
    transform: translateY(-2px);
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.3);
}

.format-controls {
    display: flex;
    gap: 20px;
    background: rgba(0, 0, 0, 0.3);
    padding: 15px 25px;
    border-radius: 12px;
    border: 2px solid rgba(255, 255, 255, 0.3);
}

.format-controls label {
    display: flex;
    align-items: center;
    gap: 8px;
    cursor: pointer;
    font-weight: 500;
    transition: all 0.3s ease;
}

.format-controls label:hover {
    color: #ffd700;
}

.format-controls input[type="radio"] {
    cursor: pointer;
    width: 18px;
    height: 18px;
    accent-color: #ffd700;
}

/* ==================== CLOCKS GRID ==================== */

.clocks-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: 25px;
    margin-bottom: 40px;
    animation: fadeIn 0.8s ease-out 0.4s backwards;
}

@keyframes fadeIn {
    from {
        opacity: 0;
    }
    to {
        opacity: 1;
    }
}

/* ==================== CLOCK CARD ==================== */

.clock-card {
    background: rgba(0, 0, 0, 0.4);
    border: 2px solid rgba(255, 255, 255, 0.2);
    border-radius: 16px;
    padding: 30px;
    text-align: center;
    backdrop-filter: blur(10px);
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
}

.clock-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: linear-gradient(90deg, #667eea, #764ba2, #667eea);
    animation: shimmer 2s infinite;
}

@keyframes shimmer {
    0%, 100% { opacity: 0.5; }
    50% { opacity: 1; }
}

.clock-card:hover {
    background: rgba(0, 0, 0, 0.6);
    border-color: rgba(255, 255, 255, 0.4);
    transform: translateY(-8px);
    box-shadow: 0 16px 40px rgba(0, 0, 0, 0.3);
}

.city-name {
    font-size: 22px;
    font-weight: bold;
    color: #ffd700;
    margin-bottom: 8px;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.timezone-info {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.6);
    margin-bottom: 15px;
}

.digital-clock {
    font-size: 48px;
    font-weight: 300;
    color: #fff;
    font-family: 'Courier New', monospace;
    letter-spacing: 3px;
    margin: 20px 0;
    text-shadow: 0 0 20px rgba(255, 215, 0, 0.3);
    animation: clockGlow 2s infinite alternate;
}

@keyframes clockGlow {
    from {
        text-shadow: 0 0 20px rgba(255, 215, 0, 0.3);
    }
    to {
        text-shadow: 0 0 30px rgba(255, 215, 0, 0.6);
    }
}

.date-display {
    font-size: 14px;
    color: rgba(255, 255, 255, 0.7);
    margin-bottom: 15px;
}

.day-display {
    font-size: 13px;
    color: rgba(255, 255, 255, 0.6);
    margin-bottom: 20px;
}

.time-offset {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 20px;
    padding: 15px;
    background: rgba(255, 215, 0, 0.1);
    border-radius: 8px;
    margin-top: 15px;
}

.offset-label {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.6);
}

.offset-value {
    font-size: 16px;
    font-weight: bold;
    color: #ffd700;
    font-family: 'Courier New', monospace;
}

.remove-btn {
    position: absolute;
    top: 10px;
    right: 10px;
    width: 32px;
    height: 32px;
    background: rgba(255, 0, 0, 0.7);
    border: none;
    border-radius: 50%;
    color: #fff;
    cursor: pointer;
    font-size: 18px;
    transition: all 0.3s ease;
    display: none;
}

.clock-card:hover .remove-btn {
    display: flex;
    align-items: center;
    justify-content: center;
}

.remove-btn:hover {
    background: rgba(255, 0, 0, 1);
    transform: scale(1.1);
}

/* ==================== ADD TIMEZONE SECTION ==================== */

.add-timezone {
    text-align: center;
    margin-bottom: 40px;
    animation: slideUp 0.6s ease-out 0.6s backwards;
}

#addTimezoneBtn {
    padding: 15px 40px;
    font-size: 16px;
}

/* ==================== MODAL ==================== */

.modal {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.7);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    backdrop-filter: blur(5px);
}

.modal.hidden {
    display: none;
}

.modal-content {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    border-radius: 16px;
    padding: 40px;
    max-width: 500px;
    width: 90%;
    position: relative;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.4);
    animation: popIn 0.4s ease-out;
}

@keyframes popIn {
    from {
        opacity: 0;
        transform: scale(0.8);
    }
    to {
        opacity: 1;
        transform: scale(1);
    }
}

.modal-content h2 {
    margin-bottom: 25px;
    font-size: 28px;
    color: #fff;
}

.close-modal {
    position: absolute;
    top: 15px;
    right: 20px;
    font-size: 32px;
    color: #fff;
    cursor: pointer;
    transition: all 0.3s ease;
}

.close-modal:hover {
    color: #ffd700;
    transform: rotate(90deg);
}

.modal-form {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.modal-form label {
    font-weight: 600;
    color: rgba(255, 255, 255, 0.9);
    font-size: 14px;
}

.modal-form input,
.modal-form select {
    padding: 12px;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-radius: 8px;
    background: rgba(0, 0, 0, 0.2);
    color: #fff;
    font-size: 16px;
    transition: all 0.3s ease;
}

.modal-form input::placeholder {
    color: rgba(255, 255, 255, 0.5);
}

.modal-form input:focus,
.modal-form select:focus {
    outline: none;
    border-color: rgba(255, 215, 0, 0.6);
    background: rgba(0, 0, 0, 0.3);
    box-shadow: 0 0 15px rgba(255, 215, 0, 0.3);
}

.add-btn {
    padding: 14px;
    background: linear-gradient(135deg, #ffd700, #ffed4e);
    color: #333;
    border: none;
    border-radius: 8px;
    font-weight: bold;
    font-size: 16px;
    cursor: pointer;
    transition: all 0.3s ease;
    margin-top: 10px;
}

.add-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 20px rgba(255, 215, 0, 0.4);
}

.add-btn:active {
    transform: translateY(0);
}

/* ==================== RESPONSIVE DESIGN ==================== */

@media (max-width: 768px) {
    header h1 {
        font-size: 32px;
    }

    .subtitle {
        font-size: 14px;
    }

    .controls {
        flex-direction: column;
        align-items: center;
        gap: 15px;
    }

    .search-box {
        flex-direction: column;
        width: 100%;
    }

    .search-box input {
        width: 100%;
    }

    .format-controls {
        width: 100%;
        justify-content: center;
    }

    .clocks-grid {
        grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
        gap: 15px;
    }

    .clock-card {
        padding: 20px;
    }

    .digital-clock {
        font-size: 36px;
        letter-spacing: 2px;
    }

    .city-name {
        font-size: 18px;
    }

    .modal-content {
        padding: 25px;
    }

    .modal-content h2 {
        font-size: 22px;
    }
}

@media (max-width: 480px) {
    header h1 {
        font-size: 24px;
    }

    .clocks-grid {
        grid-template-columns: 1fr;
    }

    .digital-clock {
        font-size: 28px;
    }

    .search-box input {
        font-size: 14px;
    }

    .time-offset {
        flex-direction: column;
        gap: 10px;
    }
}

/* ==================== UTILITY CLASSES ==================== */

.gmt-positive {
    color: #4ade80;
}

.gmt-negative {
    color: #f87171;
}

.gmt-zero {
    color: #fbbf24;
}
